package com.seaquake6324.civitas.presentation.client;
import net.minecraft.client.renderer.culling.Frustum;import net.minecraft.client.renderer.debug.DebugRenderer;import net.minecraft.gizmos.*;import net.minecraft.util.debug.DebugValueAccess;import net.minecraft.world.phys.*;import net.minecraft.core.BlockPos;
/** World-space node and segment preview for the bounded patrol drawing mode. */
public final class PatrolRoutePreviewRenderer implements DebugRenderer.SimpleDebugRenderer{public void emitGizmos(double x,double y,double z,DebugValueAccess values,Frustum frustum,float partial){var nodes=PatrolRoutePreview.nodes();for(int i=0;i<nodes.size();i++){BlockPos node=nodes.get(i);Gizmos.cuboid(new AABB(node).inflate(.025),GizmoStyle.strokeAndFill(0xDDA9D879,2F,0x24A9D879));if(i>0){BlockPos before=nodes.get(i-1);AABB segment=new AABB(Math.min(before.getX(),node.getX())+.42,Math.min(before.getY(),node.getY())+.42,Math.min(before.getZ(),node.getZ())+.42,Math.max(before.getX(),node.getX())+.58,Math.max(before.getY(),node.getY())+.58,Math.max(before.getZ(),node.getZ())+.58);Gizmos.cuboid(segment,GizmoStyle.stroke(0xAAA9D879,1F));}}BlockPos target=PatrolRoutePreview.target();if(target!=null){boolean valid=PatrolRoutePreview.locallyValid();Gizmos.cuboid(new AABB(target).inflate(.015),GizmoStyle.strokeAndFill(valid?0xDD66D995:0xDDE06666,2F,valid?0x2866D995:0x28E06666));}}
}
